mapper.sql:
WHERE 1 = 1

  AND UPPER(H.hs_code) LIKE '%' || UPPER(#{hsCode}) || '%'


  AND UPPER(H.hs_name) LIKE '%' || UPPER(#{hsName}) || '%'


  AND C.hs_class_level_cd = #{hsClassLevelCd}


  AND NVL(C.use_yn, 'Y') = #{useYn}

mapper.select:
SELECT hs_code , hs_name , hs_tariff_rate , hs_class_level_cd , hs_class_nm , hs_class_desc , parent_hs_class_cd , selectable_yn , sort_sn , use_yn FROM ( SELECT ROWNUM AS row_no , hs_code , hs_name , hs_tariff_rate , hs_class_level_cd , hs_class_nm , hs_class_desc , parent_hs_class_cd , selectable_yn , sort_sn , use_yn FROM ( SELECT
FROM hs_code H LEFT JOIN hs_class C ON C.hs_class_cd = H.hs_code
ORDER BY H.hs_code ASC ) WHERE ROWNUM <= #{endRow} ) WHERE row_no >= #{startRow}

mapper.update:
UPDATE hs_code
SET
      hs_name = #{hsName}
    , hs_tariff_rate = #{hsTariffRate}
WHERE hs_code = #{hsCode}

UPDATE hs_class
SET
      hs_class_nm = #{hsClassNm}
    , hs_class_desc = #{hsClassDesc}
    , use_yn = #{useYn}
WHERE hs_class_cd = #{hsCode}

UPDATE hs_class
SET use_yn = #{useYn}
WHERE hs_class_cd = #{hsCode}
